// Bridge key: canonical "x1,y1,x2,y2" where endpoint with smaller (x, then y) sorts first
export function getBridgeKey(island1, island2) {
  const a = { x: island1.x, y: island1.y };
  const b = { x: island2.x, y: island2.y };
  if (a.x < b.x || (a.x === b.x && a.y < b.y)) {
    return `${a.x},${a.y},${b.x},${b.y}`;
  }
  return `${b.x},${b.y},${a.x},${a.y}`;
}

// Check if two islands are adjacent (same row/col, no island between them)
function areAdjacent(islands, from, to) {
  if (from.x !== to.x && from.y !== to.y) return false;
  if (from.x === to.x && from.y === to.y) return false;

  if (from.x === to.x) {
    // Vertical
    const minY = Math.min(from.y, to.y);
    const maxY = Math.max(from.y, to.y);
    for (const island of islands) {
      if (island.id === from.id || island.id === to.id) continue;
      if (island.x === from.x && island.y > minY && island.y < maxY) return false;
    }
  } else {
    // Horizontal
    const minX = Math.min(from.x, to.x);
    const maxX = Math.max(from.x, to.x);
    for (const island of islands) {
      if (island.id === from.id || island.id === to.id) continue;
      if (island.y === from.y && island.x > minX && island.x < maxX) return false;
    }
  }
  return true;
}

// Check if a bridge between from and to would cross any existing bridge
function wouldCross(islands, bridges, from, to) {
  const isHorizontal = from.y === to.y;

  for (const [key, count] of bridges.entries()) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const [x1, y1, x2, y2] = parts;

    // Check if segments cross
    if (isHorizontal) {
      // New bridge is horizontal, check against vertical existing bridges
      if (y1 === y2) continue; // both horizontal, can't cross (parallel)
      // Existing is vertical (x1 === x2)
      const newMinX = Math.min(from.x, to.x);
      const newMaxX = Math.max(from.x, to.x);
      const newY = from.y;
      const existMinY = Math.min(y1, y2);
      const existMaxY = Math.max(y1, y2);
      const existX = x1;

      if (existX > newMinX && existX < newMaxX && newY > existMinY && newY < existMaxY) {
        return true;
      }
    } else {
      // New bridge is vertical, check against horizontal existing bridges
      if (x1 === x2) continue; // both vertical, can't cross (parallel)
      // Existing is horizontal (y1 === y2)
      const newMinY = Math.min(from.y, to.y);
      const newMaxY = Math.max(from.y, to.y);
      const newX = from.x;
      const existMinX = Math.min(x1, x2);
      const existMaxX = Math.max(x1, x2);
      const existY = y1;

      if (existY > newMinY && existY < newMaxY && newX > existMinX && newX < existMaxX) {
        return true;
      }
    }
  }
  return false;
}

// Compute current bridge counts per island
export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const island of islands) {
    counts.set(island.id, 0);
  }

  for (const [key, count] of bridges.entries()) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const [x1, y1, x2, y2] = parts;

    // Find which islands these coordinates belong to
    for (const island of islands) {
      if ((island.x === x1 && island.y === y1) || (island.x === x2 && island.y === y2)) {
        counts.set(island.id, (counts.get(island.id) || 0) + count);
      }
    }
  }
  return counts;
}

// Check if adding delta bridges is valid
export function canAddBridge(islands, bridges, from, to, delta) {
  // Degenerate case
  if (from.id === to.id) {
    return { valid: false, error: "Cannot connect island to itself" };
  }

  // Check adjacency
  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: "Cannot connect non-adjacent islands" };
  }

  const key = getBridgeKey(from, to);
  const current = bridges.get(key) || 0;
  const newCount = current + delta;

  // Check max 2
  if (newCount > 2) {
    return { valid: false, error: "Max 2 bridges per pair" };
  }

  // Check island capacity
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) || 0;
  const toCount = counts.get(to.id) || 0;

  if (fromCount + delta > from.value) {
    return { valid: false, error: "Island would exceed its number" };
  }
  if (toCount + delta > to.value) {
    return { valid: false, error: "Island would exceed its number" };
  }

  // Check crossing
  // Temporarily remove this bridge to avoid self-intersection check
  const tempBridges = new Map(bridges);
  tempBridges.delete(key);
  if (newCount > 0 && wouldCross(islands, tempBridges, from, to)) {
    return { valid: false, error: "Bridges would cross" };
  }

  return { valid: true, error: null };
}

// Check connectivity: all islands reachable from each other via bridges
export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;
  if (islands.length === 1) return true;

  // Build adjacency list
  const adj = new Map();
  for (const island of islands) {
    adj.set(island.id, []);
  }

  for (const [key, count] of bridges.entries()) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const [x1, y1, x2, y2] = parts;

    let id1 = null, id2 = null;
    for (const island of islands) {
      if (island.x === x1 && island.y === y1) id1 = island.id;
      if (island.x === x2 && island.y === y2) id2 = island.id;
    }
    if (id1 !== null && id2 !== null) {
      adj.get(id1).push(id2);
      adj.get(id2).push(id1);
    }
  }

  // BFS from first island
  const visited = new Set();
  const queue = [islands[0].id];
  visited.add(islands[0].id);

  while (queue.length > 0) {
    const curr = queue.shift();
    for (const neighbor of adj.get(curr)) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }

  return visited.size === islands.length;
}

// Check victory condition
export function isVictory(islands, bridges) {
  // Check all counts satisfied
  const counts = computeCurrentCounts(islands, bridges);
  for (const island of islands) {
    if ((counts.get(island.id) || 0) !== island.value) return false;
  }

  // Check no bridges cross
  const bridgeList = [];
  for (const [key, count] of bridges.entries()) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    bridgeList.push(parts);
  }

  for (let i = 0; i < bridgeList.length; i++) {
    for (let j = i + 1; j < bridgeList.length; j++) {
      const [ax1, ay1, ax2, ay2] = bridgeList[i];
      const [bx1, by1, bx2, by2] = bridgeList[j];

      const aHoriz = ay1 === ay2;
      const bHoriz = by1 === by2;

      if (aHoriz && !bHoriz) {
        const minAX = Math.min(ax1, ax2), maxAX = Math.max(ax1, ax2);
        const minBY = Math.min(by1, by2), maxBY = Math.max(by1, by2);
        if (bx1 > minAX && bx1 < maxAX && ay1 > minBY && ay1 < maxBY) return false;
      } else if (!aHoriz && bHoriz) {
        const minBX = Math.min(bx1, bx2), maxBX = Math.max(bx1, bx2);
        const minAY = Math.min(ay1, ay2), maxAY = Math.max(ay1, ay2);
        if (ax1 > minBX && ax1 < maxBX && by1 > minAY && by1 < maxAY) return false;
      }
    }
  }

  // Check connectivity
  return checkConnectivity(islands, bridges);
}
