import React, { useState, useEffect, useCallback, useRef } from 'react';
import { puzzles } from './data/puzzles.js';
import { getBridgeKey, canAddBridge, isVictory } from './utils/hashiLogic.js';

const GRID_SIZE = 40;
const SVG_WIDTH = 800;
const SVG_HEIGHT = 600;
const ISLAND_RADIUS = 16;
const BRIDGE_OFFSET = 4;

function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const [bridges, setBridges] = useState(new Map());
  const [selectedIsland, setSelectedIsland] = useState(null);
  const [cursorIslandId, setCursorIslandId] = useState(0);
  const [errorMessage, setErrorMessage] = useState(null);
  const [victory, setVictory] = useState(false);

  const puzzle = puzzles[puzzleIndex];
  const islands = puzzle.islands;

  // Reset state when puzzle changes
  const handlePuzzleChange = (e) => {
    const idx = parseInt(e.target.value, 10);
    setPuzzleIndex(idx);
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMessage(null);
    setVictory(false);
  };

  const handleReset = () => {
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMessage(null);
    setVictory(false);
  };

  // Toggle bridge between two islands
  const toggleBridge = useCallback((fromIsland, toIsland) => {
    const key = getBridgeKey(fromIsland, toIsland);
    const current = bridges.get(key) || 0;

    if (current >= 2) {
      // Cycle back to 0
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setErrorMessage(null);
      setVictory(false);
      // Check victory after removal
      if (isVictory(islands, newBridges)) {
        setVictory(true);
      }
      return true;
    }

    // Try to add one bridge
    const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
    if (!result.valid) {
      setErrorMessage(result.error);
      setSelectedIsland(null);
      return false;
    }

    const newBridges = new Map(bridges);
    newBridges.set(key, current + 1);
    setBridges(newBridges);
    setErrorMessage(null);
    setVictory(false);
    if (isVictory(islands, newBridges)) {
      setVictory(true);
    }
    return true;
  }, [bridges, islands]);

  // Mouse click on island
  const handleIslandClick = useCallback((island) => {
    setCursorIslandId(island.id);
    if (selectedIsland === null) {
      setSelectedIsland(island.id);
    } else if (selectedIsland === island.id) {
      setSelectedIsland(null);
    } else {
      const fromIsland = islands.find(i => i.id === selectedIsland);
      toggleBridge(fromIsland, island);
      setSelectedIsland(null);
    }
  }, [selectedIsland, islands, toggleBridge]);

  // Right-click / Ctrl+click on bridge line to remove
  const handleBridgeRemove = useCallback((key, e) => {
    e.preventDefault();
    e.stopPropagation();
    const newBridges = new Map(bridges);
    newBridges.delete(key);
    setBridges(newBridges);
    setErrorMessage(null);
    setVictory(false);
    if (isVictory(islands, newBridges)) {
      setVictory(true);
    }
  }, [bridges, islands]);

  const handleBridgeClick = useCallback((key, e) => {
    if (e.ctrlKey) {
      e.preventDefault();
      e.stopPropagation();
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setErrorMessage(null);
      setVictory(false);
      if (isVictory(islands, newBridges)) {
        setVictory(true);
      }
    }
  }, [bridges, islands]);

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e) => {
      const currentIsland = islands.find(i => i.id === cursorIslandId);
      if (!currentIsland) return;

      if (e.key === 'Escape') {
        setSelectedIsland(null);
        return;
      }

      if (e.key === 'Enter') {
        handleIslandClick(currentIsland);
        return;
      }

      let targetIsland = null;

      if (e.key === 'ArrowRight') {
        // Find nearest island to the right
        const candidates = islands.filter(i => i.x > currentIsland.x);
        if (candidates.length > 0) {
          candidates.sort((a, b) => {
            const distA = Math.abs(a.x - currentIsland.x) + Math.abs(a.y - currentIsland.y);
            const distB = Math.abs(b.x - currentIsland.x) + Math.abs(b.y - currentIsland.y);
            return distA - distB;
          });
          targetIsland = candidates[0];
        }
      } else if (e.key === 'ArrowLeft') {
        const candidates = islands.filter(i => i.x < currentIsland.x);
        if (candidates.length > 0) {
          candidates.sort((a, b) => {
            const distA = Math.abs(a.x - currentIsland.x) + Math.abs(a.y - currentIsland.y);
            const distB = Math.abs(b.x - currentIsland.x) + Math.abs(b.y - currentIsland.y);
            return distA - distB;
          });
          targetIsland = candidates[0];
        }
      } else if (e.key === 'ArrowDown') {
        const candidates = islands.filter(i => i.y > currentIsland.y);
        if (candidates.length > 0) {
          candidates.sort((a, b) => {
            const distA = Math.abs(a.x - currentIsland.x) + Math.abs(a.y - currentIsland.y);
            const distB = Math.abs(b.x - currentIsland.x) + Math.abs(b.y - currentIsland.y);
            return distA - distB;
          });
          targetIsland = candidates[0];
        }
      } else if (e.key === 'ArrowUp') {
        const candidates = islands.filter(i => i.y < currentIsland.y);
        if (candidates.length > 0) {
          candidates.sort((a, b) => {
            const distA = Math.abs(a.x - currentIsland.x) + Math.abs(a.y - currentIsland.y);
            const distB = Math.abs(b.x - currentIsland.x) + Math.abs(b.y - currentIsland.y);
            return distA - distB;
          });
          targetIsland = candidates[0];
        }
      }

      if (targetIsland) {
        setCursorIslandId(targetIsland.id);
        e.preventDefault();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [cursorIslandId, islands, handleIslandClick]);

  // Render bridges
  const renderBridges = () => {
    const lines = [];
    for (const [key, count] of bridges.entries()) {
      if (count === 0) continue;
      const parts = key.split(',').map(Number);
      const [x1, y1, x2, y2] = parts;
      const px1 = x1 * GRID_SIZE;
      const py1 = y1 * GRID_SIZE;
      const px2 = x2 * GRID_SIZE;
      const py2 = y2 * GRID_SIZE;

      if (count === 1) {
        lines.push(
          <line
            key={key}
            x1={px1}
            y1={py1}
            x2={px2}
            y2={py2}
            stroke="#0f0"
            strokeWidth="2"
            style={{ cursor: 'pointer' }}
            onClick={(e) => handleBridgeClick(key, e)}
            onContextMenu={(e) => handleBridgeRemove(key, e)}
          />
        );
      } else if (count === 2) {
        const isHorizontal = y1 === y2;
        const offset = BRIDGE_OFFSET;
        if (isHorizontal) {
          lines.push(
            <line
              key={`${key}-a`}
              x1={px1}
              y1={py1 - offset}
              x2={px2}
              y2={py2 - offset}
              stroke="#0f0"
              strokeWidth="2"
              style={{ cursor: 'pointer' }}
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeRemove(key, e)}
            />
          );
          lines.push(
            <line
              key={`${key}-b`}
              x1={px1}
              y1={py1 + offset}
              x2={px2}
              y2={py2 + offset}
              stroke="#0f0"
              strokeWidth="2"
              style={{ cursor: 'pointer' }}
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeRemove(key, e)}
            />
          );
        } else {
          lines.push(
            <line
              key={`${key}-a`}
              x1={px1 - offset}
              y1={py1}
              x2={px2 - offset}
              y2={py2}
              stroke="#0f0"
              strokeWidth="2"
              style={{ cursor: 'pointer' }}
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeRemove(key, e)}
            />
          );
          lines.push(
            <line
              key={`${key}-b`}
              x1={px1 + offset}
              y1={py1}
              x2={px2 + offset}
              y2={py2}
              stroke="#0f0"
              strokeWidth="2"
              style={{ cursor: 'pointer' }}
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeRemove(key, e)}
            />
          );
        }
      }
    }
    return lines;
  };

  // Render islands
  const renderIslands = () => {
    return islands.map(island => {
      const px = island.x * GRID_SIZE;
      const py = island.y * GRID_SIZE;
      const isSelected = selectedIsland === island.id;

      return (
        <g key={`island-${island.id}`} onClick={() => handleIslandClick(island)} style={{ cursor: 'pointer' }}>
          <circle
            cx={px}
            cy={py}
            r={ISLAND_RADIUS}
            fill="#000"
            stroke={isSelected ? "#ff0" : "#0f0"}
            strokeWidth={isSelected ? 3 : 2}
          />
          <text
            x={px}
            y={py}
            textAnchor="middle"
            dominantBaseline="central"
            fill="#0f0"
            fontSize="14"
            fontFamily="'Courier New', monospace"
          >
            {island.value}
